import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o,c as i,f as l}from"./app-f83986bb.js";const t={},a=l('<h1 id="登录" tabindex="-1"><a class="header-anchor" href="#登录" aria-hidden="true">#</a> 登录</h1><h2 id="登录方案" tabindex="-1"><a class="header-anchor" href="#登录方案" aria-hidden="true">#</a> 登录方案</h2><blockquote><p>什么是session? session从字面意思来讲，是会话。它是一种会话技术。</p></blockquote><blockquote><p>使用session方式</p></blockquote><ol><li>浏览器向服务器发起请求</li><li>服务器查询到用户信息后放在session中，并返回sessionId存放在cookie中</li><li>下次请求只需验证session中是否有用户信息，来避免重复登录</li></ol><blockquote><p>使用JWT的方式,采用较多</p></blockquote><ol><li>用户在登录成功，使用用户信息构造JWT token放在cookie中，或者保存到localStorage中</li><li>下一次登录将token放在cookie中或者请求头中携带到后端服务器</li><li>服务器端使用过滤器或拦截器进行校验处理，对token进行解析获取用户信息放在上下文中</li></ol><blockquote><p>为什么使用JWT?</p></blockquote><p>session存放于对应的服务器中，适用于单体应用，对于分布式应用来说，不适用。</p><h3 id="单点登录" tabindex="-1"><a class="header-anchor" href="#单点登录" aria-hidden="true">#</a> 单点登录</h3><p>对应用的用户信息和菜单权限统一管理</p><blockquote><p>身份认证授权方式</p></blockquote><ul><li>credential</li><li>Authorization code</li><li>password</li><li>implicit</li></ul><blockquote><p>内部多个应用登录</p></blockquote><p>网关 -》 auth服务,业务服务A,B</p><ol><li>登录A,判断token是否存在，若不存在，携带信息重定向到auth登录页面</li><li>缓存前一次请求，登录成功后，携带授权码重定向到系统A</li><li>系统A拿着code获取token</li><li>下一次请求拿着token,在网关校验，再转到对应服务</li></ol><blockquote><p>第三发授权登录</p></blockquote><h1 id="jwt" tabindex="-1"><a class="header-anchor" href="#jwt" aria-hidden="true">#</a> JWT</h1><p>JWT token由三部分组成:</p><ul><li>header 头 包含格式和签名算法，常用rsa算法</li><li>payload 载荷 主体信息</li><li>signature 签名 header和payload使用base64加密，signature使用加密后的头和载荷以及密钥加密形成</li></ul>',20),s=[a];function c(n,r){return o(),i("div",null,s)}const u=e(t,[["render",c],["__file","登录相关.html.vue"]]);export{u as default};
